" BOPF approach (deprecated) — DO NOT use for new development
" Node definition, action class, validation class — separate artifacts

" RAP approach (current) — everything in BDEF
managed implementation in class ZBP_PurchOrder unique;
define behavior for ZI_PurchOrder alias PurchOrder
persistent table zpurch_order
lock master
{
  create; update; delete;
  validation checkVendor on save { field VendorId; }
  action approvePO result [1] $self;
}

@UI.lineItem: [{ position: 10, label: 'Order ID' }]
@UI.selectionField: [{ position: 10 }]
@UI.identification: [{ position: 10 }]
key order_id as OrderId,

@UI.lineItem: [{ position: 20, label: 'Customer' }]
@UI.selectionField: [{ position: 20 }]
customer_id as CustomerId,

@UI.lineItem: [{ position: 30,
  criticality: 'StatusCriticality',
  label: 'Status' }]
status as Status,

status_criticality as StatusCriticality
" Result: List Report with filter bar, color-coded status column
" Zero JS written

" Extending standard RAP CDS view
extend view entity I_SalesOrder with
{
  zsales_order_ext.zz_project_code as ZzProjectCode
}

" Extending behavior definition
extension for ZI_SalesOrder
  implementation in class ZBP_SalesOrder_Ext unique;
{
  field ( mandatory ) ZzProjectCode;
  validation validateProjectCode on save
    { field ZzProjectCode; }
}

@UI.headerInfo: { typeName: 'Vendor',
                   typeNamePlural: 'Vendors',
                   title: { type: #STANDARD, value: 'VendorId' },
                   description: { value: 'VendorName' } }
define root view entity ZI_Vendor as select from zvendor
{
  @UI.facet: [{ id: 'GeneralInfo', type: #IDENTIFICATION_REFERENCE,
                label: 'General Information', position: 10 }]
  @UI.lineItem:     [{ position: 10 }]
  @UI.identification: [{ position: 10 }]
  @UI.selectionField: [{ position: 10 }]
  key vendor_id  as VendorId,
  @UI.lineItem:     [{ position: 20 }]
  @UI.identification: [{ position: 20 }]
      vendor_name as VendorName
}

" BDEF with proper draft setup
managed implementation in class ZBP_SalesOrder unique;
define behavior for ZI_SalesOrder alias SalesOrder
persistent table zsales_order
lock master
draft table zdt_sales_order      " Separate draft table
etag master LastChangedAt        " Etag for optimistic lock
{
  create; update; delete;
  draft action Edit;
  draft action Activate;
  draft action Discard;
  draft action Resume;
  draft determine action Prepare; " Validation before activate
  field ( readonly ) OrderId, CreatedAt, LastChangedAt;
}

" WRONG — missing array brackets
@UI.lineItem: { position: 10 }  " Wrong! No square brackets
key order_id as OrderId,

" CORRECT — proper array syntax
@UI.lineItem:     [{ position: 10, label: 'Order ID' }]
@UI.selectionField: [{ position: 10 }]
@UI.identification: [{ position: 10 }]
key order_id as OrderId,

" Criticality — must reference integer field
@UI.lineItem: [{ position: 40,
  criticality: 'StatusCriticality',  " Must be INT field
  criticalityRepresentation: #WITH_ICON }]
status as Status,
status_criticality as StatusCriticality  " 0=grey 1=red 3=green

" DCL — Access Control for RAP entity
@EndUserText.label: 'Sales Order Access Control'
@MappingRole: true
define role ZI_SalesOrder_Auth
{
  grant select on ZI_SalesOrder
    where ( CompanyCode = aspect pfcg_auth(
      zsales_order_auth, actvt, '03' )
    );
}

" CDS view annotation
@AccessControl.authorizationCheck: #CHECK  " Not #NOT_REQUIRED
define root view entity ZI_SalesOrder ...

" SU53 check after authorization failure:
" Transaction: SU53 > Display Last Failed Check
" Shows: missing auth object, field, value

