" Pure ABAP approach — zero JavaScript Fiori app

" Step 1: RAP CDS with UI Annotations
@UI.headerInfo: { typeName: 'Order',
                   typeNamePlural: 'Orders',
                   title: { value: 'OrderId' } }
define root view entity ZI_SalesOrder ...
{
  @UI.lineItem: [{ position: 10 }]
  @UI.selectionField: [{ position: 10 }]
  key order_id as OrderId,
  @UI.lineItem: [{ position: 20 }]
      status   as Status
}
" Step 2: BDEF with create, update, delete
" Step 3: Service Definition + Service Binding (OData V4)
" Step 4: ADT Preview = working Fiori List Report
" Result: Full Fiori app — 0 lines of JavaScript written

" Managed RAP — framework handles DB persistence
managed implementation in class ZBP_SalesOrder unique;
define behavior for ZI_SalesOrder
persistent table zsales_order  " Framework writes here
lock master
{
  create; update; delete;  " Framework handles these
  validation validateDates on save { ... }
}
" Developer implements: validateDates
" Developer does NOT implement: create/update/delete

" Unmanaged RAP — developer handles DB persistence
unmanaged implementation in class ZBP_MatDoc unique;
define behavior for ZI_MatDoc
{  " No 'persistent table' declaration
  create;
}
" Developer implements: create (calls BAPI)
" Developer manages: mapped, failed, reported
" Framework does NOT touch the database
